// Hàm tạo truyện mới
import axios from "axios";

const createComic = async (name, otherName, status, content, author, activate, thumbnail, token) => {
    try {
        const response = await axios.post('http://localhost:8080/api/admin/comics',
            {name, otherName, status, content, author, activate, thumbnail},
            {
                headers: {
                    Authorization: `Bearer ${token}`,
                }
            })
        // Gọi hàm fetchGenre để làm mới danh sách
        // const updatedList = await fetchGenre(token);
        return {
            success: response.data.body,
            // updatedList
        };// Trả về kết quả thành công và danh sách mới
    } catch (error) {
        // Trả về lỗi nếu có
        if (error.response) {
            throw new Error(error.response.data.message);
        } else {
            throw new Error('Đã xảy ra lỗi không xác định.');
        }
    }
}

export {createComic};
